logger = logging.getLogger()
logger.setLevel(logging.INFO)

s3 = boto3.client("s3")
sns = boto3.client("sns")

OUTPUT_BUCKET = os.environ.get("OUTPUT_BUCKET")
OUTPUT_PREFIX = os.environ.get("OUTPUT_PREFIX", "processed/")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN")


def build_result_key(source_key: str) -> str:
    filename = source_key.split("/")[-1]
    return f"{OUTPUT_PREFIX.rstrip('/')}/{filename}.json"


def process_image_bytes(image_bytes: bytes, bucket: str, key: str) -> dict:
    return {
        "source_bucket": bucket,
        "source_key": key,
        "status": "processed",
        "size_bytes": len(image_bytes),
        "message": "Image received and processed by MVP handler"
    }


def publish_notification(topic_arn: str, message: dict, subject: str = "Image Processing Result") -> dict:
    return sns.publish(
        TopicArn=topic_arn,
        Subject=subject,
        Message=json.dumps(message)
    )


def write_result_to_s3(bucket: str, key: str, result: dict) -> dict:
    return s3.put_object(
        Bucket=bucket,
        Key=key,
        Body=json.dumps(result).encode("utf-8"),
        ContentType="application/json"
    )


def handle_record(record: dict) -> dict:
    bucket = record["s3"]["bucket"]["name"]
    key = unquote_plus(record["s3"]["object"]["key"])

    logger.info("Processing object from S3: bucket=%s key=%s", bucket, key)

    response = s3.get_object(Bucket=bucket, Key=key)
    image_bytes = response["Body"].read()

    result = process_image_bytes(image_bytes, bucket, key)

    target_bucket = OUTPUT_BUCKET or bucket
    result_key = build_result_key(key)
    write_resp = write_result_to_s3(target_bucket, result_key, result)

    logger.info(
        "Wrote processing result to S3: bucket=%s key=%s etag=%s",
        target_bucket,
        result_key,
        write_resp.get("ETag")
    )

    notification_response = None
    if SNS_TOPIC_ARN:
        notification_payload = {
            "event": "image_processed",
            "result_location": {
                "bucket": target_bucket,
                "key": result_key
            },
            "result": result
        }
        notification_response = publish_notification(SNS_TOPIC_ARN, notification_payload)
        logger.info(
            "Published SNS notification: topic=%s message_id=%s",
            SNS_TOPIC_ARN,
            notification_response.get("MessageId")
        )

    return {
        "source_bucket": bucket,
        "source_key": key,
        "output_bucket": target_bucket,
        "output_key": result_key,
        "sns_message_id": notification_response.get("MessageId") if notification_response else None
    }


def lambda_handler(event, context):
    logger.info("Received event: %s", json.dumps(event))

    processed = []
    errors = []

    records = event.get("Records", [])
    for record in records:
        try:
            if record.get("eventSource") == "aws:s3":
                processed.append(handle_record(record))
            else:
                logger.warning("Skipping unsupported record: %s", record)
        except Exception as exc:
            error_info = {
                "error": str(exc),
                "traceback": traceback.format_exc(),
                "record": record
            }
            logger.error("Error processing record: %s", json.dumps(error_info))
            errors.append(error_info)

    result = {
        "processed_count": len(processed),
        "error_count": len(errors),
        "processed": processed,
        "errors": errors
    }

    logger.info("Lambda execution result: %s", json.dumps(result))
    return {
        "statusCode": 200 if not errors else 207,
        "body": json.dumps(result)
    }